('3cdd9d66-6fb9-407b-9e2f-9b8a1e14fcd4', '7313055', 'Lauro de Freitas', '<div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b>DISTÂNCIAS: 50 MINUTOS DE SALVADOR/BA - ESSA CIDADE FAZ PARTE DA REGIÃO METROPOLITANA DE SALVADOR/BA</b></div><div></div></div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b>LOCAL DE EXECUÇÃO:&nbsp;Unidades de Saúde do Município de Lauro de Freitas/BA, incluindo UPAs, PA, Hospital Jorge Novis e Complexo de Saúde</b></div><div></div></div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><div><b><font color="#2563eb">Lote 01 (Cardiologia): 1 médico cardiologista (para os laudos) + infraestrutura técnica.</font></b></div><div><b style="font-size: 0.875rem; color: rgb(12, 54, 14);">Lote 02 (Radiologia):</b><span style="font-size: 0.875rem; color: rgb(12, 54, 14);"> 1 médico radiologista (laudos) + </span><font color="#dc2626" style="font-size: 0.875rem;">1 técnico em radiologia supervisor </font><span style="font-size: 0.875rem; color: rgb(12, 54, 14);">(comprovação de vínculo) + </span><font color="#dc2626" style="font-size: 0.875rem;">equipe de técnicos</font><span style="font-size: 0.875rem;"><font color="#0c360e"> para operar os equipamentos. </font><b style=""><font color="#dc2626">EXIGE CRTR</font></b></span></div><div><b style="font-size: 0.875rem; color: rgb(12, 54, 14);">Lote 03 (Mamografia): </b><span style="font-size: 0.875rem; color: rgb(12, 54, 14);">1 médico radiologista (laudos) + equipe de</span><font color="#dc2626" style="font-size: 0.875rem;"> técnicos em radiologia</font><span style="font-size: 0.875rem; color: rgb(12, 54, 14);"> (para realizar os exames).&nbsp;</span><span style="color: rgb(220, 38, 38); font-weight: bolder; font-size: 0.875rem;">EXIGE CRTR</span></div></div><div></div></div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b><font color="#dc2626"><u>EQUIPAMENTOS - FORNECER TUDO:</u></font></b></div><div><span style="font-size: 0.875rem;"><b style=""><font color="#2563eb">• Lote 01: Fornecimento em comodato de computadores, software, aparelho de ECG, impressora, e todos os materiais de consumo (papel, tonner, etc.).</font></b></span></div><div><div>• Lote 02: Fornecimento em comodato de equipamento de Raio-X digital, CR, impressora DRY, nobreak, software PACS, acessórios radiológicos (aventais de chumbo, etc.) e materiais de consumo.</div><div>• Lote 03: A contratada deve dispor de equipe, sistema PACS e fornecer os insumos para a realização dos exames nas dependências da contratante.</div></div><div></div></div><p><br></p><div><br></div>Objeto: CONTRATAÇÃO DE EMPRESA ESPECIALIZADA NA PRESTAÇÃO DE SERVIÇOS DE TELEDIAGNÓSTICO, ABRANGENDO A REALIZAÇÃO DE EXAMES DE IMAGEM DE MÉDIA E ALTA COMPLEXIDADE, COM EMISSÃO DE LAUDOS, FORNECIMENTO DE EQUIPAMENTOS EM REGIME DE CESSÃO E SUPRIMENTO DE MATERIAIS DE CONSUMO, VISANDO ATENDER ÀS NECESSIDADES DAS UNIDADES DE SAÚDE DO MUNICÍPIO DE LAURO DE FREITAS BA', '3853560.00', NULL, NULL, 'descarte_edital', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'UrL  https://portal.licitanet.com.br/acesso-visitante/WkpxaWw1S2s=', '2026-02-25T18:04:44.182Z', '2026-02-27T19:04:05.516Z', '7313055', 'Lauro de Freitas', 'Pregão Eletrônico', '2026-03-10T12:00:00.000Z', '{"Abaixo de 500mil/ANO","LICITANET"}', 'n8n', '7313055', 'PE 012/2026 - Lauro de Freitas/Bahia', '{}', false, false, false, false, false, false, '{}', '{}', 'GSS', 'media', false